+        lines = run_helper(
+            CPP_HELPER,
+            {
+                "leaky.cpp": """
+                #include <cstdio>
+                #include <cstdlib>
+                #include <thread>
+
+                void work() {}
+
+                void leak_everything() {
+                    std::thread worker(work);
+                    void* buf = malloc(256);
+                    FILE* handle = fopen("/tmp/demo.txt", "w");
+                    (void)worker;
+                    (void)buf;
+                    (void)handle;
+                }
+                """,
+            },
+            prefix="ubs-cpp-resource-helper-",
+        )
+        entries = parse(lines)
+        kinds = {kind for _, kind, _ in entries}
