+    def test_cpp_helper_respects_cleanup(self) -> None:
+        lines = run_helper(
+            CPP_HELPER,
+            {
+                "clean.cpp": """
+                #include <cstdio>
+                #include <cstdlib>
+                #include <thread>
+
+                void work() {}
+
+                void tidy() {
+                    std::thread worker(work);
+                    worker.join();
+
+                    void* buf = malloc(256);
+                    free(buf);
+
+                    FILE* handle = fopen("/tmp/demo.txt", "w");
+                    fclose(handle);
+                }
+                """,
+            },
+            prefix="ubs-cpp-resource-helper-",
+        )
